//! GQL Queries
//! Interface to the rpc for the gql schema defined in `crates/sui-indexer-alt-graphql/schema.graphql`.
//! Built in modules for epochs, transactions, objects, and checkpoints.
//! No GQL type escapes this module. From here we return structures defined in this crate
//! or bcs encoded data of runtime structures.
//!
//! Most of these query types are generated by cynic using the schema through the web UI:
//! `https://generator.cynic-rs.dev/`

#![allow(unused)]

use anyhow::Context;
use anyhow::Error;
use anyhow::anyhow;
use cynic::QueryBuilder;
use fastcrypto::encoding::Base64 as FastCryptoBase64;
use fastcrypto::encoding::Encoding;
use itertools::Itertools;

use crate::gql::client::GraphQLClient;

// Register the schema which was loaded in the build.rs call.
#[cynic::schema("rpc")]
mod schema {
    use chrono::{DateTime as ChronoDateTime, Utc};
    cynic::impl_scalar!(u64, UInt53);
    cynic::impl_scalar!(ChronoDateTime<Utc>, DateTime);
}

pub(crate) mod txn_query {
    use super::*;
    use fastcrypto::traits::ToFromBytes;
    use sui_types::signature::GenericSignature;
    use sui_types::transaction::{
        Transaction as SuiTransaction, TransactionData, VerifiedTransaction,
    };

    use crate::TransactionInfo;

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "Base64")]
    pub(crate) struct Base64(pub String);

    #[derive(cynic::QueryVariables)]
    pub(crate) struct TransactionDataArgs {
        pub digest: String,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "TransactionDataArgs")]
    pub(crate) struct Query {
        #[arguments(digest: $digest)]
        transaction: Option<Transaction>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct Transaction {
        transaction_bcs: Option<Base64>,
        signatures: Vec<UserSignature>,
        effects: Option<TransactionEffects>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct UserSignature {
        signature_bytes: Option<Base64>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct TransactionEffects {
        checkpoint: Option<Checkpoint>,
        effects_bcs: Option<Base64>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct Checkpoint {
        sequence_number: u64,
    }

    pub(crate) async fn query(
        digest: String,
        client: &GraphQLClient,
    ) -> Result<Option<TransactionInfo>, Error> {
        let query = Query::build(TransactionDataArgs {
            digest: digest.clone(),
        });
        let response = client
            .run_query(&query)
            .await
            .context("Failed to run transaction query")?;

        let Some(transaction) = response.data.and_then(|txn| txn.transaction) else {
            return Ok(None);
        };

        let txn_data: TransactionData = bcs::from_bytes(
            &FastCryptoBase64::decode(
                &transaction
                    .transaction_bcs
                    .ok_or_else(|| {
                        anyhow!(format!(
                            "Transaction data not available (None) for digest: {}",
                            digest
                        ),)
                    })?
                    .0,
            )
            .context(format!(
                "Transaction data does not decode for digest: {}",
                digest
            ))?,
        )
        .context(format!(
            "Cannot deserialize transaction data for digest {}",
            digest
        ))?;

        let signatures: Vec<GenericSignature> = transaction
            .signatures
            .into_iter()
            .map(|sig| {
                let encoded = sig
                    .signature_bytes
                    .ok_or_else(|| anyhow!("Missing signatureBytes for transaction {}", digest))?;
                let bytes = FastCryptoBase64::decode(&encoded.0).context(format!(
                    "User signature does not decode for digest: {}",
                    digest
                ))?;
                GenericSignature::from_bytes(&bytes).map_err(|e| {
                    anyhow!("User signature parse failed for digest {}: {}", digest, e)
                })
            })
            .collect::<Result<_, _>>()?;

        let effect_frag = transaction
            .effects
            .ok_or_else(|| anyhow!("Missing effects in transaction data response"))?;
        let effects: sui_types::effects::TransactionEffects = bcs::from_bytes(
            &FastCryptoBase64::decode(
                &effect_frag
                    .effects_bcs
                    .ok_or_else(|| anyhow!("Missing effects bcs in transaction data response"))?
                    .0,
            )
            .context(format!(
                "Transaction effects do not decode for digest: {}",
                digest
            ))?,
        )
        .context(format!(
            "Cannot deserialize transaction effects for digest {}",
            digest
        ))?;

        let checkpoint = effect_frag
            .checkpoint
            .ok_or_else(|| anyhow!("Missing checkpoint in transaction data response"))?
            .sequence_number;

        let transaction = VerifiedTransaction::new_unchecked(
            SuiTransaction::from_generic_sig_data(txn_data, signatures),
        );

        Ok(Some(TransactionInfo {
            transaction,
            effects,
            checkpoint,
        }))
    }
}

pub(crate) mod available_range_query {
    use super::*;

    #[derive(cynic::QueryVariables)]
    pub(crate) struct AvailableRangeArgs {
        pub type_name: String,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "AvailableRangeArgs")]
    pub(crate) struct Query {
        service_config: ServiceConfig,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "AvailableRangeArgs")]
    pub(crate) struct ServiceConfig {
        #[arguments(type: $type_name)]
        available_range: AvailableRange,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct AvailableRange {
        first: Option<Checkpoint>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct Checkpoint {
        sequence_number: u64,
    }

    /// Query the lowest available checkpoint sequence number for a given type
    /// (e.g., "Checkpoint" or "Transaction").
    pub(crate) async fn query(type_name: &str, client: &GraphQLClient) -> Result<u64, Error> {
        let operation = Query::build(AvailableRangeArgs {
            type_name: type_name.to_owned(),
        });
        let response = client.run_query(&operation).await.context(format!(
            "Failed to query availableRange for type '{}'",
            type_name,
        ))?;
        let data = response
            .data
            .ok_or_else(|| anyhow!("No data in availableRange response for '{}'", type_name))?;
        Ok(data
            .service_config
            .available_range
            .first
            .map(|c| c.sequence_number)
            .unwrap_or(0))
    }
}

pub(crate) mod address_owned_objects_query {
    use anyhow::Context;
    use anyhow::Error;
    use anyhow::anyhow;
    use cynic::QueryBuilder as _;
    use sui_types::base_types::ObjectID;
    use sui_types::base_types::ObjectRef;
    use sui_types::base_types::SequenceNumber;
    use sui_types::base_types::SuiAddress as SuiAddressType;
    use sui_types::digests::ObjectDigest;
    use sui_types::messages_checkpoint::CheckpointSequenceNumber;

    use crate::gql::GraphQLClient;
    use crate::gql::queries::schema;

    const PAGE_SIZE: i32 = 50;

    /// Lightweight metadata for an address-owned object at a checkpoint.
    #[derive(Clone, Debug, Eq, PartialEq)]
    pub(crate) struct AddressOwnedObject {
        pub(crate) object_ref: ObjectRef,
    }

    #[derive(cynic::QueryVariables)]
    pub(crate) struct AddressObjectsArgs {
        pub sequence_number: Option<u64>,
        pub address: SuiAddress,
        pub first: Option<i32>,
        pub after: Option<String>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "AddressObjectsArgs",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Query {
        #[arguments(sequenceNumber: $sequence_number)]
        checkpoint: Option<Checkpoint>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "AddressObjectsArgs",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Checkpoint {
        query: Option<ScopedQuery>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "AddressObjectsArgs",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct ScopedQuery {
        #[arguments(address: $address)]
        address: Option<Address>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "AddressObjectsArgs",
        graphql_type = "Address",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Address {
        #[arguments(first: $first, after: $after)]
        objects: Option<MoveObjectConnection>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "AddressObjectsArgs",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct MoveObjectConnection {
        nodes: Vec<MoveObject>,
        page_info: PageInfo,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) struct PageInfo {
        has_next_page: bool,
        end_cursor: Option<String>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) struct MoveObject {
        address: SuiAddress,
        version: Option<u64>,
        digest: Option<String>,
    }

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "SuiAddress")]
    pub(crate) struct SuiAddress(pub String);

    pub(crate) async fn query(
        address: SuiAddressType,
        checkpoint: CheckpointSequenceNumber,
        client: &GraphQLClient,
    ) -> Result<Vec<AddressOwnedObject>, Error> {
        let mut entries = Vec::new();
        let mut cursor = None;

        loop {
            let operation = Query::build(AddressObjectsArgs {
                sequence_number: Some(checkpoint),
                address: SuiAddress(address.to_string()),
                first: Some(PAGE_SIZE),
                after: cursor,
            });
            let response = client
                .run_query(&operation)
                .await
                .with_context(|| format!("failed to query owned objects for {address}"))?;

            let data = response.data.ok_or_else(|| {
                anyhow!(
                    "missing data in address objects query response for {address}: {:?}",
                    response.errors,
                )
            })?;
            let checkpoint_data = data
                .checkpoint
                .ok_or_else(|| anyhow!("checkpoint {checkpoint} not found for address seeding"))?;
            let scoped_query = checkpoint_data
                .query
                .ok_or_else(|| anyhow!("missing checkpoint-scoped query for address seeding"))?;
            let Some(address_data) = scoped_query.address else {
                return Ok(entries);
            };
            let Some(objects) = address_data.objects else {
                return Ok(entries);
            };

            for node in objects.nodes {
                entries.push(decode_move_object(node)?);
            }

            if !objects.page_info.has_next_page {
                break;
            }
            cursor = objects.page_info.end_cursor;
        }

        Ok(entries)
    }

    fn decode_move_object(node: MoveObject) -> Result<AddressOwnedObject, Error> {
        let object_id = node
            .address
            .0
            .parse::<ObjectID>()
            .with_context(|| format!("invalid seed object id {}", node.address.0))?;
        let digest = node
            .digest
            .ok_or_else(|| anyhow!("seed object {object_id} is missing digest"))?
            .parse::<ObjectDigest>()
            .with_context(|| format!("invalid seed object digest for {object_id}"))?;
        let version = node
            .version
            .ok_or_else(|| anyhow!("seed object {object_id} is missing version"))?;

        Ok(AddressOwnedObject {
            object_ref: (object_id, SequenceNumber::from_u64(version), digest),
        })
    }

    #[cfg(test)]
    mod tests {
        use sui_types::base_types::ObjectID;
        use sui_types::object::Object;
        use sui_types::object::Owner as SuiOwner;
        use wiremock::Mock;
        use wiremock::MockServer;
        use wiremock::ResponseTemplate;
        use wiremock::matchers::body_partial_json;
        use wiremock::matchers::method;
        use wiremock::matchers::path;

        use super::*;
        use crate::Node;

        fn address_objects_response(
            nodes: Vec<serde_json::Value>,
            has_next_page: bool,
            end_cursor: Option<&str>,
        ) -> serde_json::Value {
            serde_json::json!({
                "data": {
                    "checkpoint": {
                        "query": {
                            "address": {
                                "objects": {
                                    "nodes": nodes,
                                    "pageInfo": {
                                        "hasNextPage": has_next_page,
                                        "endCursor": end_cursor,
                                    }
                                }
                            }
                        }
                    }
                }
            })
        }

        fn missing_address_response() -> serde_json::Value {
            serde_json::json!({
                "data": {
                    "checkpoint": {
                        "query": {
                            "address": null
                        }
                    }
                }
            })
        }

        fn missing_objects_response() -> serde_json::Value {
            serde_json::json!({
                "data": {
                    "checkpoint": {
                        "query": {
                            "address": {
                                "objects": null
                            }
                        }
                    }
                }
            })
        }

        fn address_object_node(object: &Object) -> serde_json::Value {
            serde_json::json!({
                "address": object.id().to_string(),
                "version": object.version().value(),
                "digest": object.digest().to_string(),
            })
        }

        #[tokio::test]
        async fn query_paginates_address_owned_object_refs_without_owner() {
            let server = MockServer::start().await;
            let owner = SuiAddressType::random_for_testing_only();
            let first = Object::with_id_owner_version_for_testing(
                ObjectID::random(),
                SequenceNumber::from_u64(7),
                SuiOwner::AddressOwner(owner),
            );
            let second = Object::with_id_owner_version_for_testing(
                ObjectID::random(),
                SequenceNumber::from_u64(8),
                SuiOwner::ConsensusAddressOwner {
                    start_version: SequenceNumber::from_u64(8),
                    owner,
                },
            );
            Mock::given(method("POST"))
                .and(path("/"))
                .and(body_partial_json(serde_json::json!({
                    "variables": { "after": null }
                })))
                .respond_with(
                    ResponseTemplate::new(200).set_body_json(address_objects_response(
                        vec![address_object_node(&first)],
                        true,
                        Some("cursor-1"),
                    )),
                )
                .mount(&server)
                .await;
            Mock::given(method("POST"))
                .and(path("/"))
                .and(body_partial_json(serde_json::json!({
                    "variables": { "after": "cursor-1" }
                })))
                .respond_with(
                    ResponseTemplate::new(200).set_body_json(address_objects_response(
                        vec![address_object_node(&second)],
                        false,
                        None,
                    )),
                )
                .mount(&server)
                .await;

            let gql = GraphQLClient::new(Node::Custom(server.uri()), "test")
                .expect("graphql client should build");
            let entries = query(owner, 10, &gql)
                .await
                .expect("address seed should resolve");

            assert_eq!(entries.len(), 2);
            assert_eq!(entries[0].object_ref, first.compute_object_reference());
            assert_eq!(entries[1].object_ref, second.compute_object_reference());

            let requests = server
                .received_requests()
                .await
                .expect("wiremock should record requests");
            let request_body: serde_json::Value = requests[0]
                .body_json()
                .expect("request body should be json");
            let query = request_body
                .get("query")
                .and_then(serde_json::Value::as_str)
                .expect("query string should be present");
            assert!(query.contains("address(address: $address)"));
            assert!(query.contains("version"));
            assert!(query.contains("digest"));
            assert!(!query.contains("owner"));
            assert!(!query.contains("contents"));
            assert!(!query.contains("balance"));
        }

        #[tokio::test]
        async fn query_returns_empty_for_missing_address_or_objects() {
            let owner = SuiAddressType::random_for_testing_only();

            let server = MockServer::start().await;
            Mock::given(method("POST"))
                .and(path("/"))
                .respond_with(ResponseTemplate::new(200).set_body_json(missing_address_response()))
                .mount(&server)
                .await;
            let gql = GraphQLClient::new(Node::Custom(server.uri()), "test")
                .expect("graphql client should build");

            assert!(
                query(owner, 10, &gql)
                    .await
                    .expect("missing address should resolve")
                    .is_empty()
            );

            let server = MockServer::start().await;
            Mock::given(method("POST"))
                .and(path("/"))
                .respond_with(ResponseTemplate::new(200).set_body_json(missing_objects_response()))
                .mount(&server)
                .await;
            let gql = GraphQLClient::new(Node::Custom(server.uri()), "test")
                .expect("graphql client should build");

            assert!(
                query(owner, 10, &gql)
                    .await
                    .expect("missing objects should resolve")
                    .is_empty()
            );
        }
    }
}

pub(crate) mod object_inventory_query {
    use anyhow::Context;
    use anyhow::Error;
    use anyhow::anyhow;
    use cynic::QueryBuilder as _;
    use sui_types::base_types::ObjectID;
    use sui_types::base_types::ObjectRef;
    use sui_types::base_types::SequenceNumber;
    use sui_types::digests::ObjectDigest;
    use sui_types::messages_checkpoint::CheckpointSequenceNumber;

    use crate::gql::GraphQLClient;
    use crate::gql::queries::schema;

    const PAGE_SIZE: i32 = 50;

    #[derive(Clone, Debug, Eq, PartialEq)]
    pub(crate) struct InventoryObject {
        pub(crate) object_ref: ObjectRef,
    }

    #[derive(cynic::QueryVariables)]
    pub(crate) struct ObjectInventoryArgs {
        pub sequence_number: Option<u64>,
        pub filter: ObjectFilter,
        pub first: Option<i32>,
        pub after: Option<String>,
    }

    #[derive(cynic::InputObject, Clone, Debug)]
    #[cynic(
        graphql_type = "ObjectFilter",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct ObjectFilter {
        pub owner: Option<SuiAddress>,
        pub owner_kind: Option<OwnerKind>,
        #[cynic(rename = "type")]
        pub type_: Option<String>,
    }

    #[derive(cynic::Enum, Clone, Copy, Debug)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) enum OwnerKind {
        Address,
        Object,
        Shared,
        Immutable,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "ObjectInventoryArgs",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Query {
        #[arguments(sequenceNumber: $sequence_number)]
        checkpoint: Option<Checkpoint>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "ObjectInventoryArgs",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Checkpoint {
        query: Option<ScopedQuery>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "ObjectInventoryArgs",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct ScopedQuery {
        #[arguments(first: $first, after: $after, filter: $filter)]
        objects: Option<ObjectConnection>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "ObjectInventoryArgs",
        graphql_type = "ObjectConnection",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct ObjectConnection {
        nodes: Vec<Object>,
        page_info: PageInfo,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) struct PageInfo {
        has_next_page: bool,
        end_cursor: Option<String>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(graphql_type = "Object", schema_module = "crate::gql::queries::schema")]
    pub(crate) struct Object {
        address: SuiAddress,
        version: Option<u64>,
        digest: Option<String>,
    }

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "SuiAddress")]
    pub(crate) struct SuiAddress(pub String);

    pub(crate) async fn query_object_owner(
        owner: ObjectID,
        checkpoint: CheckpointSequenceNumber,
        client: &GraphQLClient,
    ) -> Result<Vec<InventoryObject>, Error> {
        query(
            ObjectFilter {
                owner: Some(SuiAddress(owner.to_string())),
                owner_kind: Some(OwnerKind::Object),
                type_: None,
            },
            checkpoint,
            client,
        )
        .await
    }

    pub(crate) async fn query_type(
        type_filter: String,
        checkpoint: CheckpointSequenceNumber,
        client: &GraphQLClient,
    ) -> Result<Vec<InventoryObject>, Error> {
        query(
            ObjectFilter {
                owner: None,
                owner_kind: None,
                type_: Some(type_filter),
            },
            checkpoint,
            client,
        )
        .await
    }

    async fn query(
        filter: ObjectFilter,
        checkpoint: CheckpointSequenceNumber,
        client: &GraphQLClient,
    ) -> Result<Vec<InventoryObject>, Error> {
        let mut entries = Vec::new();
        let mut cursor = None;

        loop {
            let operation = Query::build(ObjectInventoryArgs {
                sequence_number: Some(checkpoint),
                filter: filter.clone(),
                first: Some(PAGE_SIZE),
                after: cursor,
            });
            let response = client
                .run_query(&operation)
                .await
                .with_context(|| format!("failed to query object inventory at {checkpoint}"))?;

            let data = response.data.ok_or_else(|| {
                anyhow!(
                    "missing data in object inventory response at checkpoint {checkpoint}: {:?}",
                    response.errors,
                )
            })?;
            let checkpoint_data = data
                .checkpoint
                .ok_or_else(|| anyhow!("checkpoint {checkpoint} not found for object inventory"))?;
            let scoped_query = checkpoint_data
                .query
                .ok_or_else(|| anyhow!("missing checkpoint-scoped query for object inventory"))?;

            let Some(objects) = scoped_query.objects else {
                return Ok(entries);
            };

            for node in objects.nodes {
                entries.push(decode_object(node)?);
            }

            if !objects.page_info.has_next_page {
                break;
            }
            cursor = objects.page_info.end_cursor;
        }

        Ok(entries)
    }

    fn decode_object(node: Object) -> Result<InventoryObject, Error> {
        let object_id = node
            .address
            .0
            .parse::<ObjectID>()
            .with_context(|| format!("invalid inventory object id {}", node.address.0))?;
        let digest = node
            .digest
            .ok_or_else(|| anyhow!("inventory object {object_id} is missing digest"))?
            .parse::<ObjectDigest>()
            .with_context(|| format!("invalid inventory object digest for {object_id}"))?;
        let version = node
            .version
            .ok_or_else(|| anyhow!("inventory object {object_id} is missing version"))?;

        Ok(InventoryObject {
            object_ref: (object_id, SequenceNumber::from_u64(version), digest),
        })
    }
}

pub(crate) mod object_seed_query {
    use sui_types::base_types::ObjectID;
    use sui_types::base_types::SequenceNumber;
    use sui_types::base_types::SuiAddress as SuiAddressType;
    use sui_types::digests::ObjectDigest;
    use sui_types::messages_checkpoint::CheckpointSequenceNumber;

    use super::address_owned_objects_query::AddressOwnedObject;
    use super::*;

    #[derive(Clone, Debug, Eq, PartialEq)]
    pub(crate) enum ObjectSeedMetadata {
        Missing,
        NonAddressOwned,
        AddressOwned(AddressOwnedObject),
    }

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "SuiAddress")]
    pub(crate) struct SuiAddress(pub String);

    #[derive(cynic::InputObject, Debug)]
    #[cynic(graphql_type = "ObjectKey")]
    pub(crate) struct ObjectKey {
        pub address: SuiAddress,
        pub version: Option<u64>,
        pub root_version: Option<u64>,
        pub at_checkpoint: Option<u64>,
    }

    #[derive(cynic::QueryVariables)]
    pub(crate) struct ObjectSeedArgs {
        pub keys: Vec<ObjectKey>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "ObjectSeedArgs",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Query {
        #[arguments(keys: $keys)]
        multi_get_objects: Vec<Option<ObjectSeedObject>>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(graphql_type = "Object", schema_module = "crate::gql::queries::schema")]
    pub(crate) struct ObjectSeedObject {
        version: Option<u64>,
        digest: Option<String>,
        owner: Option<Owner>,
    }

    #[derive(cynic::InlineFragments)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) enum Owner {
        AddressOwner(AddressOwner),
        ConsensusAddressOwner(ConsensusAddressOwner),
        #[cynic(fallback)]
        Other,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) struct AddressOwner {
        address: Option<OwnerAddress>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(schema_module = "crate::gql::queries::schema")]
    pub(crate) struct ConsensusAddressOwner {
        address: Option<OwnerAddress>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        graphql_type = "Address",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct OwnerAddress {
        address: SuiAddress,
    }

    const MAX_KEYS_SIZE: usize = 30;

    pub(crate) async fn query(
        object_ids: &[ObjectID],
        checkpoint: CheckpointSequenceNumber,
        client: &GraphQLClient,
    ) -> Result<Vec<ObjectSeedMetadata>, Error> {
        let mut results = Vec::with_capacity(object_ids.len());

        for object_ids in object_ids.chunks(MAX_KEYS_SIZE) {
            let keys = object_ids
                .iter()
                .map(|object_id| ObjectKey {
                    address: SuiAddress(object_id.to_string()),
                    version: None,
                    root_version: None,
                    at_checkpoint: Some(checkpoint),
                })
                .collect();
            let operation = Query::build(ObjectSeedArgs { keys });
            let response = client.run_query(&operation).await.with_context(|| {
                format!("failed to query object seeds at checkpoint {checkpoint}")
            })?;
            let data = response.data.with_context(|| {
                format!(
                    "missing data in object seed query response at checkpoint {checkpoint}: {:?}",
                    response.errors,
                )
            })?;

            if data.multi_get_objects.len() != object_ids.len() {
                return Err(anyhow!(
                    "object seed query returned {} results for {} object IDs",
                    data.multi_get_objects.len(),
                    object_ids.len(),
                ));
            }

            for (object_id, object) in object_ids.iter().copied().zip_eq(data.multi_get_objects) {
                results.push(decode_object_seed(object_id, object)?);
            }
        }

        Ok(results)
    }

    fn decode_object_seed(
        object_id: ObjectID,
        object: Option<ObjectSeedObject>,
    ) -> Result<ObjectSeedMetadata, Error> {
        let Some(object) = object else {
            return Ok(ObjectSeedMetadata::Missing);
        };
        match object.owner {
            Some(Owner::AddressOwner(owner)) => parse_owner_address(owner.address, &object_id)?,
            Some(Owner::ConsensusAddressOwner(owner)) => {
                parse_owner_address(owner.address, &object_id)?
            }
            _ => return Ok(ObjectSeedMetadata::NonAddressOwned),
        };
        let digest = object
            .digest
            .with_context(|| format!("seed object {object_id} is missing digest"))?
            .parse::<ObjectDigest>()
            .with_context(|| format!("invalid seed object digest for {object_id}"))?;
        let version = object
            .version
            .with_context(|| format!("seed object {object_id} is missing version"))?;

        Ok(ObjectSeedMetadata::AddressOwned(AddressOwnedObject {
            object_ref: (object_id, SequenceNumber::from_u64(version), digest),
        }))
    }

    fn parse_owner_address(
        address: Option<OwnerAddress>,
        object_id: &ObjectID,
    ) -> Result<SuiAddressType, Error> {
        address
            .with_context(|| format!("seed object {object_id} is missing owner address"))?
            .address
            .0
            .parse::<SuiAddressType>()
            .with_context(|| format!("invalid seed owner for object {object_id}"))
    }

    #[cfg(test)]
    mod tests {
        use sui_types::base_types::ObjectID;
        use sui_types::object::Object;
        use sui_types::object::Owner as SuiOwner;
        use wiremock::Mock;
        use wiremock::MockServer;
        use wiremock::ResponseTemplate;
        use wiremock::matchers::body_partial_json;
        use wiremock::matchers::method;
        use wiremock::matchers::path;

        use super::*;
        use crate::Node;

        fn object_seed_response(nodes: Vec<serde_json::Value>) -> serde_json::Value {
            serde_json::json!({
                "data": {
                    "multiGetObjects": nodes,
                }
            })
        }

        fn address_owned_object_node(object: &Object, owner: SuiAddressType) -> serde_json::Value {
            serde_json::json!({
                "version": object.version().value(),
                "digest": object.digest().to_string(),
                "owner": {
                    "__typename": "AddressOwner",
                    "address": { "address": owner.to_string() },
                }
            })
        }

        fn consensus_owned_object_node(
            object: &Object,
            owner: SuiAddressType,
        ) -> serde_json::Value {
            serde_json::json!({
                "version": object.version().value(),
                "digest": object.digest().to_string(),
                "owner": {
                    "__typename": "ConsensusAddressOwner",
                    "address": { "address": owner.to_string() },
                }
            })
        }

        fn assert_object_seed_query_shape(query: &str) {
            assert!(query.contains("multiGetObjects"));
            assert!(query.contains("version"));
            assert!(query.contains("digest"));
            assert!(query.contains("... on AddressOwner"));
            assert!(query.contains("... on ConsensusAddressOwner"));
            assert!(!query.contains("objectBcs"));

            let object_selection_before_owner = query
                .split("multiGetObjects")
                .nth(1)
                .expect("query should include multiGetObjects")
                .split("owner")
                .next()
                .expect("query should include owner");
            assert!(
                !object_selection_before_owner
                    .lines()
                    .any(|line| line.trim() == "address"),
                "object seed query should not request Object.address",
            );
        }

        #[tokio::test]
        async fn query_returns_address_owned_metadata_without_object_bcs() {
            let server = MockServer::start().await;
            let owner = SuiAddressType::random_for_testing_only();
            let first = Object::with_id_owner_version_for_testing(
                ObjectID::random(),
                SequenceNumber::from_u64(7),
                SuiOwner::AddressOwner(owner),
            );
            let second = Object::with_id_owner_version_for_testing(
                ObjectID::random(),
                SequenceNumber::from_u64(8),
                SuiOwner::ConsensusAddressOwner {
                    start_version: SequenceNumber::from_u64(8),
                    owner,
                },
            );
            let missing = ObjectID::random();

            Mock::given(method("POST"))
                .and(path("/"))
                .and(body_partial_json(serde_json::json!({
                    "variables": {
                        "keys": [
                            {
                                "address": first.id().to_string(),
                                "atCheckpoint": 10,
                            },
                            {
                                "address": missing.to_string(),
                                "atCheckpoint": 10,
                            },
                            {
                                "address": second.id().to_string(),
                                "atCheckpoint": 10,
                            },
                        ],
                    }
                })))
                .respond_with(
                    ResponseTemplate::new(200).set_body_json(object_seed_response(vec![
                        address_owned_object_node(&first, owner),
                        serde_json::Value::Null,
                        consensus_owned_object_node(&second, owner),
                    ])),
                )
                .mount(&server)
                .await;

            let gql = GraphQLClient::new(Node::Custom(server.uri()), "test")
                .expect("graphql client should build");
            let entries = query(&[first.id(), missing, second.id()], 10, &gql)
                .await
                .expect("object seeds should resolve");

            assert_eq!(entries.len(), 3);
            assert_eq!(
                entries[0],
                ObjectSeedMetadata::AddressOwned(AddressOwnedObject {
                    object_ref: first.compute_object_reference(),
                })
            );
            assert_eq!(entries[1], ObjectSeedMetadata::Missing);
            assert_eq!(
                entries[2],
                ObjectSeedMetadata::AddressOwned(AddressOwnedObject {
                    object_ref: second.compute_object_reference(),
                })
            );

            let requests = server
                .received_requests()
                .await
                .expect("wiremock should record requests");
            let request_body: serde_json::Value = requests[0]
                .body_json()
                .expect("request body should be json");
            let query = request_body
                .get("query")
                .and_then(serde_json::Value::as_str)
                .expect("query string should be present");
            assert_object_seed_query_shape(query);
        }

        #[tokio::test]
        async fn query_errors_on_malformed_object_seed_metadata() {
            let owner = SuiAddressType::random_for_testing_only();
            let object = Object::with_id_owner_version_for_testing(
                ObjectID::random(),
                SequenceNumber::from_u64(7),
                SuiOwner::AddressOwner(owner),
            );

            for (node, expected_error) in [
                (
                    serde_json::json!({
                        "version": object.version().value(),
                        "digest": null,
                        "owner": {
                            "__typename": "AddressOwner",
                            "address": { "address": owner.to_string() },
                        }
                    }),
                    "missing digest",
                ),
                (
                    serde_json::json!({
                        "version": null,
                        "digest": object.digest().to_string(),
                        "owner": {
                            "__typename": "AddressOwner",
                            "address": { "address": owner.to_string() },
                        }
                    }),
                    "missing version",
                ),
                (
                    serde_json::json!({
                        "version": object.version().value(),
                        "digest": object.digest().to_string(),
                        "owner": {
                            "__typename": "AddressOwner",
                            "address": null,
                        }
                    }),
                    "missing owner address",
                ),
            ] {
                let server = MockServer::start().await;
                Mock::given(method("POST"))
                    .and(path("/"))
                    .respond_with(
                        ResponseTemplate::new(200).set_body_json(object_seed_response(vec![node])),
                    )
                    .mount(&server)
                    .await;

                let gql = GraphQLClient::new(Node::Custom(server.uri()), "test")
                    .expect("graphql client should build");
                let err = query(&[object.id()], 10, &gql)
                    .await
                    .expect_err("malformed object seed metadata should fail");

                assert!(
                    err.to_string().contains(expected_error),
                    "expected error containing {expected_error:?}, got {err:?}",
                );
            }
        }
    }
}

pub(crate) mod events_query {
    use super::*;
    use sui_types::effects::TransactionEvents;
    use sui_types::event::Event;

    const PAGE_SIZE: i32 = 50;

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "Base64")]
    pub(crate) struct Base64(pub String);

    #[derive(cynic::QueryVariables)]
    pub(crate) struct EventsArgs {
        pub digest: String,
        pub first: Option<i32>,
        pub after: Option<String>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "EventsArgs")]
    pub(crate) struct Query {
        #[arguments(digest: $digest)]
        transaction: Option<Transaction>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "EventsArgs")]
    pub(crate) struct Transaction {
        effects: Option<TransactionEffects>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "EventsArgs")]
    pub(crate) struct TransactionEffects {
        #[arguments(first: $first, after: $after)]
        events: Option<EventConnection>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct EventConnection {
        nodes: Vec<EventNode>,
        page_info: PageInfo,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(graphql_type = "Event")]
    pub(crate) struct EventNode {
        event_bcs: Option<Base64>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct PageInfo {
        has_next_page: bool,
        end_cursor: Option<String>,
    }

    /// Fetch all events for a transaction by paginating through the GraphQL
    /// events connection. Returns `None` if the transaction doesn't exist.
    /// Returns an empty `TransactionEvents` if the transaction has no events.
    pub(crate) async fn query(
        digest: &str,
        client: &GraphQLClient,
    ) -> Result<Option<TransactionEvents>, Error> {
        let mut all_events: Vec<Event> = Vec::new();
        let mut cursor: Option<String> = None;

        loop {
            let operation = Query::build(EventsArgs {
                digest: digest.to_owned(),
                first: Some(PAGE_SIZE),
                after: cursor,
            });
            let response = client
                .run_query(&operation)
                .await
                .context("Failed to run events query")?;

            let Some(connection) = response
                .data
                .and_then(|q| q.transaction)
                .and_then(|tx| tx.effects)
                .and_then(|fx| fx.events)
            else {
                if all_events.is_empty() {
                    return Ok(Some(TransactionEvents { data: vec![] }));
                }
                break;
            };

            for node in connection.nodes {
                let Some(bcs_str) = node.event_bcs else {
                    continue;
                };
                let bytes = FastCryptoBase64::decode(&bcs_str.0)
                    .context(format!("Event BCS does not decode for tx {}", digest))?;
                let event: Event = bcs::from_bytes(&bytes)
                    .context(format!("Cannot deserialize event for tx {}", digest))?;
                all_events.push(event);
            }

            if !connection.page_info.has_next_page {
                break;
            }
            cursor = connection.page_info.end_cursor;
        }

        Ok(Some(TransactionEvents { data: all_events }))
    }
}

pub(crate) mod object_query {
    use sui_types::object::Object;

    use super::*;
    use crate::{ObjectKey as GqlObjectKey, VersionQuery};

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "SuiAddress")]
    pub(crate) struct SuiAddress(pub String);

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "Base64")]
    pub(crate) struct Base64(pub String);

    #[derive(cynic::InputObject, Debug)]
    #[cynic(graphql_type = "ObjectKey")]
    pub(crate) struct ObjectKey {
        pub address: SuiAddress,
        pub version: Option<u64>,
        pub root_version: Option<u64>,
        pub at_checkpoint: Option<u64>,
    }

    #[derive(cynic::QueryVariables)]
    pub(crate) struct MultiGetObjectsVars {
        pub keys: Vec<ObjectKey>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "MultiGetObjectsVars", graphql_type = "Query")]
    pub(crate) struct MultiGetObjectsQuery {
        #[arguments(keys: $keys)]
        pub multi_get_objects: Vec<Option<ObjectFragment>>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(graphql_type = "Object", schema_module = "crate::gql::queries::schema")]
    pub(crate) struct ObjectFragment {
        #[allow(dead_code)]
        pub address: SuiAddress,
        pub version: Option<u64>,
        pub object_bcs: Option<Base64>,
    }

    #[derive(cynic::QueryVariables)]
    pub(crate) struct VersionAtCheckpointVars {
        pub sequence_number: Option<u64>,
        pub address: SuiAddress,
        pub version: Option<u64>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "VersionAtCheckpointVars",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct VersionAtCheckpointQuery {
        #[arguments(sequenceNumber: $sequence_number)]
        pub checkpoint: Option<Checkpoint>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "VersionAtCheckpointVars",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct Checkpoint {
        pub query: Option<ScopedQuery>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(
        variables = "VersionAtCheckpointVars",
        graphql_type = "Query",
        schema_module = "crate::gql::queries::schema"
    )]
    pub(crate) struct ScopedQuery {
        #[arguments(address: $address, version: $version)]
        pub object: Option<ObjectFragment>,
    }

    // Maximum number of keys to query in a single request.
    // REVIEW: not clear how this translate to the 5000B limit, so
    // we are picking a "random" and conservative number.
    const MAX_KEYS_SIZE: usize = 30;

    /// Query objects by keys and return a vector of the same length with the results, which contain
    /// an Some<(Object, Version)> tuple if the object is found, or None if not found.
    pub(crate) async fn query(
        keys: &[GqlObjectKey],
        data_store: &GraphQLClient,
    ) -> Result<Vec<Option<(Object, u64)>>, Error> {
        let mut results: Vec<Option<Option<(Object, u64)>>> = vec![None; keys.len()];
        let mut standard_indices: Vec<usize> = Vec::with_capacity(keys.len());
        let mut standard_keys: Vec<ObjectKey> = Vec::with_capacity(keys.len());

        for (idx, key) in keys.iter().cloned().enumerate() {
            match key.version_query {
                VersionQuery::VersionAtCheckpoint {
                    version,
                    checkpoint,
                } => {
                    results[idx] = Some(
                        query_version_at_checkpoint(key.object_id, version, checkpoint, data_store)
                            .await?,
                    );
                }
                _ => {
                    standard_indices.push(idx);
                    standard_keys.push(ObjectKey::from(key));
                }
            }
        }

        let mut keys = standard_keys;
        let mut key_chunks = vec![];
        while !keys.is_empty() {
            let chunk: Vec<_> = keys.drain(..MAX_KEYS_SIZE.min(keys.len())).collect();
            key_chunks.push(chunk);
        }

        let mut standard_results = vec![];

        for keys in key_chunks {
            let query: cynic::Operation<MultiGetObjectsQuery, MultiGetObjectsVars> =
                MultiGetObjectsQuery::build(MultiGetObjectsVars { keys });
            let response = data_store.run_query(&query).await?;

            let list = if let Some(data) = response.data {
                data.multi_get_objects
            } else {
                return Err(anyhow!(
                    "Missing data in transaction query response. Errors: {:?}",
                    response.errors,
                ));
            };

            standard_results.extend(
                list.into_iter()
                    .map(decode_object_fragment)
                    .collect::<Result<Vec<_>, _>>()?,
            );
        }

        for (idx, object) in standard_indices.into_iter().zip_eq(standard_results) {
            results[idx] = Some(object);
        }

        Ok(results
            .into_iter()
            .map(|result| result.expect("every query key should produce a result"))
            .collect())
    }

    async fn query_version_at_checkpoint(
        object_id: sui_types::base_types::ObjectID,
        version: u64,
        checkpoint: u64,
        data_store: &GraphQLClient,
    ) -> Result<Option<(Object, u64)>, Error> {
        let query = VersionAtCheckpointQuery::build(VersionAtCheckpointVars {
            sequence_number: Some(checkpoint),
            address: SuiAddress(object_id.to_string()),
            version: Some(version),
        });
        let response = data_store.run_query(&query).await?;
        let checkpoint = response
            .data
            .and_then(|data| data.checkpoint)
            .ok_or_else(|| anyhow!("Missing checkpoint in object query response"))?;
        let scoped_query = checkpoint
            .query
            .ok_or_else(|| anyhow!("Missing checkpoint-scoped query in object response"))?;

        decode_object_fragment(scoped_query.object)
    }

    fn decode_object_fragment(
        frag: Option<ObjectFragment>,
    ) -> Result<Option<(Object, u64)>, Error> {
        match frag {
            Some(frag) => {
                let b64 = frag
                    .object_bcs
                    .ok_or_else(|| anyhow!("Object bcs is None for object"))?
                    .0;
                let bytes = FastCryptoBase64::decode(&b64)?;
                let obj: Object = bcs::from_bytes(&bytes)?;
                let version = frag
                    .version
                    .ok_or_else(|| anyhow!("Object version is None for object"))?;
                Ok(Some((obj, version)))
            }
            None => Ok(None),
        }
    }

    impl From<GqlObjectKey> for ObjectKey {
        fn from(key: GqlObjectKey) -> Self {
            ObjectKey {
                address: SuiAddress(key.object_id.to_string()),
                version: match key.version_query {
                    VersionQuery::Version(v) => Some(v),
                    VersionQuery::VersionAtCheckpoint {
                        version,
                        checkpoint,
                    } => Some(version),
                    _ => None,
                },
                root_version: match key.version_query {
                    VersionQuery::RootVersion(v) => Some(v),
                    _ => None,
                },
                at_checkpoint: match key.version_query {
                    VersionQuery::AtCheckpoint(v) => Some(v),
                    VersionQuery::VersionAtCheckpoint {
                        version,
                        checkpoint,
                    } => Some(checkpoint),
                    _ => None,
                },
            }
        }
    }

    #[cfg(test)]
    mod tests {
        use sui_types::base_types::ObjectID;

        use super::*;

        #[test]
        fn object_key_from_version_query_sets_only_selected_bound() {
            let object_id = ObjectID::random();

            let version_key = ObjectKey::from(GqlObjectKey {
                object_id,
                version_query: VersionQuery::Version(7),
            });
            assert_eq!(version_key.address.0, object_id.to_string());
            assert_eq!(version_key.version, Some(7));
            assert_eq!(version_key.root_version, None);
            assert_eq!(version_key.at_checkpoint, None);

            let root_version_key = ObjectKey::from(GqlObjectKey {
                object_id,
                version_query: VersionQuery::RootVersion(11),
            });
            assert_eq!(root_version_key.version, None);
            assert_eq!(root_version_key.root_version, Some(11));
            assert_eq!(root_version_key.at_checkpoint, None);

            let checkpoint_key = ObjectKey::from(GqlObjectKey {
                object_id,
                version_query: VersionQuery::AtCheckpoint(19),
            });
            assert_eq!(checkpoint_key.version, None);
            assert_eq!(checkpoint_key.root_version, None);
            assert_eq!(checkpoint_key.at_checkpoint, Some(19));

            let object_key = ObjectKey::from(GqlObjectKey {
                object_id,
                version_query: VersionQuery::VersionAtCheckpoint {
                    version: 23,
                    checkpoint: 29,
                },
            });
            assert_eq!(object_key.version, Some(23));
            assert_eq!(object_key.root_version, None);
            assert_eq!(object_key.at_checkpoint, Some(29));
        }

        #[test]
        fn decode_object_fragment_returns_none_for_missing_object() {
            assert_eq!(decode_object_fragment(None).unwrap(), None);
        }
    }
}

pub(crate) mod latest_checkpoint_query {
    use super::*;
    use sui_types::messages_checkpoint::CheckpointSequenceNumber;

    #[derive(cynic::QueryFragment)]
    #[cynic(graphql_type = "Query")]
    pub(crate) struct Query {
        checkpoint: Option<Checkpoint>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct Checkpoint {
        sequence_number: CheckpointSequenceNumber,
    }

    pub(crate) async fn query(data_store: &GraphQLClient) -> Result<Option<u64>, Error> {
        let query = Query::build(());
        let response = data_store.run_query(&query).await?;
        let Some(checkpoint) = response
            .data
            .and_then(|data| data.checkpoint)
            .map(|c| c.sequence_number)
        else {
            return Ok(None);
        };

        Ok(Some(checkpoint))
    }
}

pub(crate) mod checkpoint_query {
    use fastcrypto::traits::ToFromBytes;
    use roaring::RoaringBitmap;
    use sui_types::{
        crypto::{AggregateAuthoritySignature, AuthorityStrongQuorumSignInfo},
        messages_checkpoint::{
            CertifiedCheckpointSummary, CheckpointContents, CheckpointSummary, VerifiedCheckpoint,
        },
    };

    use super::*;

    #[derive(cynic::Scalar, Debug, Clone)]
    #[cynic(graphql_type = "Base64")]
    pub(crate) struct Base64(pub String);

    #[derive(cynic::QueryVariables)]
    pub(crate) struct CheckpointArgs {
        pub sequence_number: Option<u64>,
    }

    #[derive(cynic::QueryFragment)]
    #[cynic(variables = "CheckpointArgs", graphql_type = "Query")]
    pub(crate) struct Query {
        #[arguments(sequenceNumber: $sequence_number)]
        checkpoint: Option<Checkpoint>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct Checkpoint {
        summary_bcs: Option<Base64>,
        content_bcs: Option<Base64>,
        validator_signatures: Option<ValidatorAggregatedSignature>,
    }

    #[derive(cynic::QueryFragment)]
    pub(crate) struct ValidatorAggregatedSignature {
        signature: Option<Base64>,
        signers_map: Vec<i32>,
    }

    /// Fetch a checkpoint by sequence number (or the latest if `None`), returning
    /// both the verified summary envelope and the decoded checkpoint contents.
    pub(crate) async fn query(
        sequence_number: Option<u64>,
        data_store: &GraphQLClient,
    ) -> Result<Option<(VerifiedCheckpoint, CheckpointContents)>, Error> {
        let query = Query::build(CheckpointArgs { sequence_number });
        let response = data_store.run_query(&query).await?;
        let Some(checkpoint) = response.data.and_then(|data| data.checkpoint) else {
            return Ok(None);
        };
        Ok(Some(decode_checkpoint(checkpoint)?))
    }

    fn decode_checkpoint(
        checkpoint: Checkpoint,
    ) -> Result<(VerifiedCheckpoint, CheckpointContents), Error> {
        let contents: CheckpointContents =
            decode_bcs(checkpoint.content_bcs, "checkpoint contents")?;
        let summary: CheckpointSummary = decode_bcs(checkpoint.summary_bcs, "checkpoint summary")?;
        let Some(validator_signatures) = checkpoint.validator_signatures else {
            return Err(anyhow!(
                "Missing validator signatures in checkpoint response"
            ));
        };

        let signature_bytes = FastCryptoBase64::decode(
            &validator_signatures
                .signature
                .ok_or_else(|| anyhow!("Missing aggregated checkpoint signature"))?
                .0,
        )
        .context("checkpoint signature does not decode")?;
        let signature = AggregateAuthoritySignature::from_bytes(&signature_bytes)
            .context("cannot deserialize aggregated checkpoint signature")?;
        let signers_map = validator_signatures
            .signers_map
            .into_iter()
            .map(|signer| {
                u32::try_from(signer)
                    .map_err(|_| anyhow!("negative signer index in checkpoint signature"))
            })
            .collect::<Result<RoaringBitmap, Error>>()?;

        let certified = CertifiedCheckpointSummary::new_from_data_and_sig(
            summary.clone(),
            AuthorityStrongQuorumSignInfo {
                epoch: summary.epoch,
                signature,
                signers_map,
            },
        );
        if summary.content_digest != *contents.digest() {
            return Err(anyhow!(
                "checkpoint summary content digest does not match decoded contents: \
                 summary={:?} contents={:?}",
                summary.content_digest,
                contents.digest(),
            ));
        }
        // TODO: should we fetch the committee and pass that into try_into_verified instead of
        // constructing this with new_unchecked?
        Ok((VerifiedCheckpoint::new_unchecked(certified), contents))
    }

    fn decode_bcs<T>(field: Option<Base64>, label: &str) -> Result<T, Error>
    where
        T: serde::de::DeserializeOwned,
    {
        let bytes = FastCryptoBase64::decode(
            &field
                .ok_or_else(|| anyhow!("Missing {} in checkpoint response", label))?
                .0,
        )
        .with_context(|| format!("{} does not decode", label))?;
        bcs::from_bytes(&bytes).with_context(|| format!("cannot deserialize {}", label))
    }

    #[cfg(test)]
    mod tests {
        use std::convert::TryFrom;

        use fastcrypto::encoding::Base64 as FastCryptoBase64;
        use sui_types::test_checkpoint_data_builder::TestCheckpointBuilder;

        use super::{Base64, Checkpoint, ValidatorAggregatedSignature, decode_checkpoint};

        fn encode_bcs<T: serde::Serialize>(value: &T) -> Base64 {
            Base64(
                FastCryptoBase64::from_bytes(
                    &bcs::to_bytes(value).expect("value should serialize"),
                )
                .encoded(),
            )
        }

        #[test]
        fn decode_checkpoint_reconstructs_verified_checkpoint() {
            let checkpoint = TestCheckpointBuilder::new(7).build_checkpoint();
            let certified = checkpoint.summary;
            let contents = checkpoint.contents;

            let (decoded, decoded_contents) = decode_checkpoint(Checkpoint {
                summary_bcs: Some(encode_bcs(certified.data())),
                content_bcs: Some(encode_bcs(&contents)),
                validator_signatures: Some(ValidatorAggregatedSignature {
                    signature: Some(Base64(
                        FastCryptoBase64::from_bytes(certified.auth_sig().signature.as_ref())
                            .encoded(),
                    )),
                    signers_map: certified
                        .auth_sig()
                        .signers_map
                        .iter()
                        .map(|index| i32::try_from(index).expect("test signers fit in i32"))
                        .collect(),
                }),
            })
            .expect("checkpoint should decode");

            assert_eq!(decoded.data(), certified.data());
            assert_eq!(decoded.auth_sig().epoch, certified.auth_sig().epoch);
            assert_eq!(
                decoded.auth_sig().signature.as_ref(),
                certified.auth_sig().signature.as_ref()
            );
            assert_eq!(
                decoded.auth_sig().signers_map,
                certified.auth_sig().signers_map
            );
            assert_eq!(decoded_contents.digest(), contents.digest());
        }

        #[test]
        fn decode_checkpoint_rejects_missing_validator_signatures() {
            let checkpoint = TestCheckpointBuilder::new(7).build_checkpoint();

            let error = decode_checkpoint(Checkpoint {
                summary_bcs: Some(encode_bcs(checkpoint.summary.data())),
                content_bcs: Some(encode_bcs(&checkpoint.contents)),
                validator_signatures: None,
            })
            .expect_err("missing validator signatures should fail");

            assert!(
                error
                    .to_string()
                    .contains("Missing validator signatures in checkpoint response")
            );
        }

        #[test]
        fn decode_checkpoint_rejects_negative_signer_indices() {
            let checkpoint = TestCheckpointBuilder::new(7).build_checkpoint();

            let error = decode_checkpoint(Checkpoint {
                summary_bcs: Some(encode_bcs(checkpoint.summary.data())),
                content_bcs: Some(encode_bcs(&checkpoint.contents)),
                validator_signatures: Some(ValidatorAggregatedSignature {
                    signature: Some(Base64(
                        FastCryptoBase64::from_bytes(
                            checkpoint.summary.auth_sig().signature.as_ref(),
                        )
                        .encoded(),
                    )),
                    signers_map: vec![-1],
                }),
            })
            .expect_err("negative signer index should fail");

            assert!(
                error
                    .to_string()
                    .contains("negative signer index in checkpoint signature")
            );
        }
    }
}

pub(crate) mod chain_id_query {
    use super::*;

    #[derive(cynic::QueryFragment)]
    pub(crate) struct Query {
        chain_identifier: Option<String>,
    }

    pub(crate) async fn query(data_store: &GraphQLClient) -> Result<String, Error> {
        let query = Query::build(());
        let response = data_store.run_query(&query).await?;
        let Some(chain_id) = response.data.and_then(|data| data.chain_identifier) else {
            return Err(anyhow!("Missing chain identifier"));
        };
        Ok(chain_id)
    }
}
